#include <omp.h>
#include "common.h"

#ifdef RD_WG_SIZE_0_0
#define BLOCK_SIZE RD_WG_SIZE_0_0
#elif defined(RD_WG_SIZE_0)
#define BLOCK_SIZE RD_WG_SIZE_0
#elif defined(RD_WG_SIZE)
#define BLOCK_SIZE RD_WG_SIZE
#else
#define BLOCK_SIZE 16
#endif

extern int omp_num_threads;

static void lud_diagonal_omp(float *m, int matrix_dim, int offset) {
    int i, j, tx;
    float shadow[BLOCK_SIZE * BLOCK_SIZE];

    int array_offset = offset * matrix_dim + offset;
    for (i = 0; i < BLOCK_SIZE; i++) {
        for (tx = 0; tx < BLOCK_SIZE; tx++) {
            shadow[i * BLOCK_SIZE + tx] = m[array_offset + tx];
        }
        array_offset += matrix_dim;
    }

    for (i = 0; i < BLOCK_SIZE - 1; i++) {
        for (tx = i + 1; tx < BLOCK_SIZE; tx++) {
            for (j = 0; j < i; j++) {
                shadow[tx * BLOCK_SIZE + i] -=
                    shadow[tx * BLOCK_SIZE + j] * shadow[j * BLOCK_SIZE + i];
            }
            shadow[tx * BLOCK_SIZE + i] /= shadow[i * BLOCK_SIZE + i];
        }

        for (tx = i + 1; tx < BLOCK_SIZE; tx++) {
            for (j = 0; j < i + 1; j++) {
                shadow[(i + 1) * BLOCK_SIZE + tx] -=
                    shadow[(i + 1) * BLOCK_SIZE + j] * shadow[j * BLOCK_SIZE + tx];
            }
        }
    }

    array_offset = (offset + 1) * matrix_dim + offset;
    for (i = 1; i < BLOCK_SIZE; i++) {
        for (tx = 0; tx < BLOCK_SIZE; tx++) {
            m[array_offset + tx] = shadow[i * BLOCK_SIZE + tx];
        }
        array_offset += matrix_dim;
    }
}

static void lud_perimeter_block_omp(float *m, int matrix_dim, int offset, int bx) {
    int i, j, idx;
    float dia[BLOCK_SIZE * BLOCK_SIZE];
    float peri_row[BLOCK_SIZE * BLOCK_SIZE];
    float peri_col[BLOCK_SIZE * BLOCK_SIZE];

    for (i = 0; i < BLOCK_SIZE; i++) {
        for (idx = 0; idx < BLOCK_SIZE; idx++) {
            dia[i * BLOCK_SIZE + idx] = m[(offset + i) * matrix_dim + offset + idx];
        }
    }

    for (i = 0; i < BLOCK_SIZE; i++) {
        for (idx = 0; idx < BLOCK_SIZE; idx++) {
            peri_row[i * BLOCK_SIZE + idx] =
                m[(offset + i) * matrix_dim + offset + (bx + 1) * BLOCK_SIZE + idx];
        }
    }

    for (i = 0; i < BLOCK_SIZE; i++) {
        for (idx = 0; idx < BLOCK_SIZE; idx++) {
            peri_col[i * BLOCK_SIZE + idx] =
                m[(offset + (bx + 1) * BLOCK_SIZE + i) * matrix_dim + offset + idx];
        }
    }

    for (idx = 0; idx < BLOCK_SIZE; idx++) {
        for (i = 1; i < BLOCK_SIZE; i++) {
            for (j = 0; j < i; j++) {
                peri_row[i * BLOCK_SIZE + idx] -=
                    dia[i * BLOCK_SIZE + j] * peri_row[j * BLOCK_SIZE + idx];
            }
        }
    }

    for (idx = 0; idx < BLOCK_SIZE; idx++) {
        for (i = 0; i < BLOCK_SIZE; i++) {
            for (j = 0; j < i; j++) {
                peri_col[idx * BLOCK_SIZE + i] -=
                    peri_col[idx * BLOCK_SIZE + j] * dia[j * BLOCK_SIZE + i];
            }
            peri_col[idx * BLOCK_SIZE + i] /= dia[i * BLOCK_SIZE + i];
        }
    }

    for (i = 1; i < BLOCK_SIZE; i++) {
        for (idx = 0; idx < BLOCK_SIZE; idx++) {
            m[(offset + i) * matrix_dim + offset + (bx + 1) * BLOCK_SIZE + idx] =
                peri_row[i * BLOCK_SIZE + idx];
        }
    }

    for (i = 0; i < BLOCK_SIZE; i++) {
        for (idx = 0; idx < BLOCK_SIZE; idx++) {
            m[(offset + (bx + 1) * BLOCK_SIZE + i) * matrix_dim + offset + idx] =
                peri_col[i * BLOCK_SIZE + idx];
        }
    }
}

static void lud_internal_block_omp(float *m, int matrix_dim, int offset, int bx, int by) {
    int tx, ty, i;
    float peri_row[BLOCK_SIZE * BLOCK_SIZE];
    float peri_col[BLOCK_SIZE * BLOCK_SIZE];

    int global_row_id = offset + (by + 1) * BLOCK_SIZE;
    int global_col_id = offset + (bx + 1) * BLOCK_SIZE;

    for (ty = 0; ty < BLOCK_SIZE; ty++) {
        for (tx = 0; tx < BLOCK_SIZE; tx++) {
            peri_row[ty * BLOCK_SIZE + tx] =
                m[(offset + ty) * matrix_dim + global_col_id + tx];
            peri_col[ty * BLOCK_SIZE + tx] =
                m[(global_row_id + ty) * matrix_dim + offset + tx];
        }
    }

    for (ty = 0; ty < BLOCK_SIZE; ty++) {
        for (tx = 0; tx < BLOCK_SIZE; tx++) {
            float sum = 0.0f;
            for (i = 0; i < BLOCK_SIZE; i++) {
                sum += peri_col[ty * BLOCK_SIZE + i] * peri_row[i * BLOCK_SIZE + tx];
            }
            m[(global_row_id + ty) * matrix_dim + global_col_id + tx] -= sum;
        }
    }
}

void lud_omp(float *m, int matrix_dim) {
    int i;
    omp_set_num_threads(omp_num_threads);

    for (i = 0; i < matrix_dim - BLOCK_SIZE; i += BLOCK_SIZE) {
        int num_blocks = (matrix_dim - i) / BLOCK_SIZE - 1;

        lud_diagonal_omp(m, matrix_dim, i);

        if (num_blocks > 0) {
#pragma omp parallel for schedule(static)
            for (int bx = 0; bx < num_blocks; bx++) {
                lud_perimeter_block_omp(m, matrix_dim, i, bx);
            }

#pragma omp parallel for collapse(2) schedule(static)
            for (int by = 0; by < num_blocks; by++) {
                for (int bx = 0; bx < num_blocks; bx++) {
                    lud_internal_block_omp(m, matrix_dim, i, bx, by);
                }
            }
        }
    }

    lud_diagonal_omp(m, matrix_dim, i);
}
